-- Run from Studio command bar: require(game.ServerScriptService.DevTools.BuildMeshLibrary).build()local ReplicatedStorage = game:GetService("ReplicatedStorage")local ServerScriptService = game:GetService("ServerScriptService")local function build()	local configs = {		ArchitectureVariants = require(ReplicatedStorage.Shared.Config.ArchitectureVariants),		MeshAssets = require(ReplicatedStorage.ConfigurationFiles.MeshAssets),		DecorationConfig = require(ReplicatedStorage.ConfigurationFiles.DecorationConfig),	}	local lib = Instance.new("Folder")	lib.Name = "MeshLibrary"	lib.Parent = ReplicatedStorage	local total = 0	local function addMesh(name, meshId, category)		if not meshId or meshId == "" or meshId:match("FILL_") then return end		local numId = tonumber(meshId:match("%d+"))		if not numId then return end		local mp = Instance.new("MeshPart")		mp.Name = name		mp.MeshId = "rbxassetid://" .. numId		mp.Anchored = true		mp.CanCollide = false		mp.Size = Vector3.new(2, 2, 2)		local catFolder = lib:FindFirstChild(category)		if not catFolder then			catFolder = Instance.new("Folder")			catFolder.Name = category			catFolder.Parent = lib		end		mp.Parent = catFolder		total = total + 1	end	for catName, catData in pairs(configs.ArchitectureVariants) do		for itemName, itemData in pairs(catData) do			for variantId, meshId in pairs(itemData.meshes) do				addMesh(variantId, meshId, "Architecture/" .. catName)			end		end	end	for itemName, variants in pairs(configs.MeshAssets.meshes) do		for variantId, meshId in pairs(variants) do			addMesh(variantId, meshId, "HarvestNodes/" .. itemName)		end	end	for _, list in pairs({ configs.DecorationConfig.garden_items, configs.DecorationConfig.cottage_items }) do		for _, item in ipairs(list) do			addMesh(item.modelName or item.id, item.meshId, "Decorations")		end	end	print("[MeshLibrary] Built " .. total .. " mesh references in ReplicatedStorage.MeshLibrary")endreturn { build = build }